let dateStr;
let ref = "main";
try {
  const inputData = $input.first();
  if (inputData && inputData.json && inputData.json.body) {
    if (inputData.json.body.date) dateStr = inputData.json.body.date;
    if (inputData.json.body.commit) ref = inputData.json.body.commit;
  }
} catch (e) {}

if (!dateStr) {
  const now = new Date();
  const gtOffset = -6 * 60;
  const gtTime = new Date(now.getTime() + gtOffset * 60000);
  const yyyy = gtTime.getUTCFullYear();
  const mm = String(gtTime.getUTCMonth() + 1).padStart(2, '0');
  const dd = String(gtTime.getUTCDate()).padStart(2, '0');
  dateStr = `${yyyy}-${mm}-${dd}`;
}

const repoOwner = "apolancog-dev";
const repoName = "centrodetutorias";
const branch = "main";
const baseRawUrl = `https://raw.githubusercontent.com/${repoOwner}/${repoName}/${ref}/content-generator/output/${dateStr}`;
const githubFilePath = `content-generator/output/${dateStr}/manifest.json`;
const cacheBuster = Date.now();

return [{
  json: {
    videoUrl: `${baseRawUrl}/vertical_video.mp4?t=${cacheBuster}`,
    date: dateStr,
    manifestUrl: `${baseRawUrl}/manifest.json?t=${cacheBuster}`,
    copyUrl: `${baseRawUrl}/copy.json?t=${cacheBuster}`,
    imageUrl: `${baseRawUrl}/feed_1080x1080.png?t=${cacheBuster}`,
    githubFilePath: githubFilePath,
    repoOwner: repoOwner,
    repoName: repoName,
    branch: branch
  }
}];

const manifestInput = $('Read manifest.json').first().json;
const copyInput = $('Read copy.json').first().json;

let manifest;
if (typeof manifestInput.data === 'string') {
  manifest = JSON.parse(manifestInput.data);
} else if (manifestInput.data) {
  manifest = manifestInput.data;
} else {
  manifest = manifestInput;
}

let copy;
if (typeof copyInput.data === 'string') {
  copy = JSON.parse(copyInput.data);
} else if (copyInput.data) {
  copy = copyInput.data;
} else {
  copy = copyInput;
}

const datesNode = $('Get Dates & Paths').first().json;

return [{
  json: {
    date: datesNode.date,
    githubFilePath: datesNode.githubFilePath,
    repoOwner: datesNode.repoOwner,
    repoName: datesNode.repoName,
    branch: datesNode.branch,
    imageUrl: datesNode.imageUrl,
    manifest,
    copy
  }
}];

