let fbStatus = "No publicado";
let igFeedStatus = "No publicado";
let igStoryStatus = "No publicado";
let tiktokStatus = "No publicado";
let hasErrors = false;

if (format === 'video') {
  // 1. Facebook Video
  try {
    const fbNode = $('Publish FB Video').first();
    if (fbNode.json.error) {
      fbStatus = `❌ Error: ${fbNode.json.error.message || JSON.stringify(fbNode.json.error)}`;
      hasErrors = true;
    } else if (fbNode.json.id) {
      fbStatus = `✅ Publicado con éxito (ID: ${fbNode.json.id})`;
    } else {
      fbStatus = `✅ Publicado con éxito`;
    }
  } catch (e) {
    fbStatus = `⚠️ No ejecutado o no verificado`;
  }

  // 2. Instagram Reel (Feed)
  try {
    const igNode = $('Publish IG Reel').first();
    if (igNode.json.error) {
      igFeedStatus = `❌ Error: ${igNode.json.error.message || JSON.stringify(igNode.json.error)}`;
      hasErrors = true;
    } else if (igNode.json.id) {
      igFeedStatus = `✅ Publicado con éxito (ID: ${igNode.json.id})`;
    } else {
      igFeedStatus = `✅ Publicado con éxito`;
    }
  } catch (e) {
    igFeedStatus = `⚠️ No ejecutado o no verificado`;
  }

  // 3. TikTok Video
  try {
    const ttNode = $('Publish TikTok Video').first();
    if (ttNode.json.error) {
      tiktokStatus = `❌ Error: ${ttNode.json.error.message || JSON.stringify(ttNode.json.error)}`;
      hasErrors = true;
    } else if (ttNode.json.data && ttNode.json.data.publish_id) {
      tiktokStatus = `✅ Publicado con éxito (Publish ID: ${ttNode.json.data.publish_id})`;
    } else {
      tiktokStatus = `✅ Publicado con éxito`;
    }
  } catch (e) {
    tiktokStatus = `⚠️ No ejecutado o no verificado`;
  }

} else {
